const workflowName = $workflow.name;
const startTime = new Date($execution.startedAt).getTime();
const endTime = Date.now();
const executionTime = ((endTime - startTime) / 1000).toFixed(2);

return [{
  json: {
    notificationType: 'success',
    workflowName: workflowName,
    status: 'success',
    message: 'Workflow terminé avec succès',
    executionTime: executionTime,
    chatId: '5992469226'
  }
}];

const items = $input.all();
 const timestamp = new Date().toISOString();
 const workflowInfo = {
   workflowName: $workflow.name,
   executionId: $execution.id,
   timestamp
 };

 // 1. Gestion des erreurs d'exécution n8n
 const errorItem = items.find(item => item.json.error !== undefined || item.error !== undefined);
 if (errorItem) {
   const error = errorItem.json.error || errorItem.error;
   return [{
     json: {
       hasError: true,
       success: false,
       errorType: 'EXECUTION_ERROR',
       message: error.message || 'Une erreur technique est survenue dans le flux',
       ...workflowInfo
     }
   }];
 }

 // 2. Extraction et validation des fichiers binaires
 let xlsxFile = null;
 let csvFile = null;

 // On parcourt tous les items pour trouver les propriétés binaires
 for (let itemIndex = 0; itemIndex < items.length; itemIndex++) {
   const item = items[itemIndex];
   if (item.binary) {
     for (const key of Object.keys(item.binary)) {
       const binary = item.binary[key];

       // Vérification si le fichier n'est pas vide
       if (binary.fileSize <= 8) continue;

       // Récupérer le contenu réel du fichier et le convertir en base64
       const buffer = await this.helpers.getBinaryDataBuffer(itemIndex, key);
       const base64Data = buffer.toString('base64');

       const fileInfo = {
         filename: binary.fileName,
         fileSize: binary.fileSize,
         mimeType: binary.mimeType,
         data: base64Data  // Contenu base64 réel
       };

       if (binary.fileExtension === 'xlsx') {
         xlsxFile = fileInfo;
       } else if (binary.fileExtension === 'csv') {
         csvFile = fileInfo;
       }
     }
   }
 }

 // 3. Validation de la présence des deux fichiers
 if (!xlsxFile || !csvFile) {
   let missingMsg = [];
   if (!csvFile) missingMsg.push("CSV 3CX");
   if (!xlsxFile) missingMsg.push("XLSX YMCS");

   return [{
     json: {
       hasError: true,
       success: false,
       errorType: 'MISSING_FILES_ERROR',
       message: `Fichiers manquants ou invalides : ${missingMsg.join(' et ')}`,
       details: {
         csvFound: !!csvFile,
         xlsxFound: !!xlsxFile
       },
       ...workflowInfo
     }
   }];
 }

 // 4. Succès
 console.log('✅ Fichiers validés : 3CX CSV et YMCS XLSX prêts.');

 return [{
   json: {
     hasError: false,
     success: true,
     message: "Validation réussie",
     files: {
       csv_3cx: csvFile,
       xlsx_ymcs: xlsxFile
     },
     ...workflowInfo
   }
 }];

