        finalModel = "SIP-T54W";
    } else if (excelModel === "SIP-T34" || excelModel === "T34") {
        finalModel = "SIP-T34W";
    } else if (excelModel === "SIP-T57" || excelModel === "T57") {
        finalModel = "SIP-T57W";
    } else if (/^T\d+/.test(excelModel)) {
        // Si commence par T sans SIP- (ex: T31P)
