const fs = require('fs');
const path = require('path');

const workflows = $input.item.json.data;
const repoPath = $('Configuration').item.json.REPO_PATH;
const workflowsDir = path.join(repoPath, 'workflows');
const timestamp = new Date().toISOString();

if (!fs.existsSync(workflowsDir)) {
  fs.mkdirSync(workflowsDir, { recursive: true });
}

const REDACTED_FIELDS = ['GIT_TOKEN'];

function redactSecrets(workflowData) {
  const clone = JSON.parse(JSON.stringify(workflowData));
  for (const node of (clone.nodes || [])) {
    const assignments = node.parameters?.assignments?.assignments;
    if (assignments) {
      for (const a of assignments) {
        if (REDACTED_FIELDS.includes(a.name)) a.value = '';
      }
    }
  }
  return clone;
}

const currentFilenames = new Set();

for (const workflow of workflows) {
  const workflowData = {
    name: workflow.name,
    nodes: workflow.nodes,
    pinData: workflow.pinData || {},
    connections: workflow.connections,
    active: workflow.active,
    settings: workflow.settings,
    versionId: workflow.versionId,
    meta: workflow.meta,
    id: workflow.id,
    tags: workflow.tags || []
  };

  const sanitizedName = workflow.name
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '');

  const filename = sanitizedName + '-' + workflow.id + '.json';
  currentFilenames.add(filename);

  fs.writeFileSync(
    path.join(workflowsDir, filename),
    JSON.stringify(redactSecrets(workflowData), null, 2),
    'utf8'
  );
}

// Full export also redacted
fs.writeFileSync(
  path.join(repoPath, 'N8N_GitHub_Daily_Backup.json'),
  JSON.stringify({ workflows: workflows.map(w => redactSecrets(w)) }, null, 2),
  'utf8'
);

// Remove orphan files
const existingFiles = fs.readdirSync(workflowsDir).filter(f => f.endsWith('.json'));
const removedFiles = [];
for (const file of existingFiles) {
  if (!currentFilenames.has(file)) {
    fs.unlinkSync(path.join(workflowsDir, file));
    removedFiles.push(file);
  }
}

return [{ json: { timestamp, workflowCount: workflows.length, removedCount: removedFiles.length, removedFiles } }];

const { execSync } = require('child_process');
const repoPath = $('Configuration').item.json.REPO_PATH;
const gitBranch = $('Configuration').item.json.GIT_BRANCH;
const gitUserName = $('Configuration').item.json.GIT_USER_NAME;
const gitUserEmail = $('Configuration').item.json.GIT_USER_EMAIL;
const gitToken = $('Configuration').item.json.GIT_TOKEN;
const timestamp = $('Process & Save All Files').item.json.timestamp;
const workflowCount = $('Process & Save All Files').item.json.workflowCount;
const removedCount = $('Process & Save All Files').item.json.removedCount;

const exec = (cmd) => execSync(
  'GIT_TERMINAL_PROMPT=0 GIT_ASKPASS=true ' + cmd,
  { encoding: 'utf8', timeout: 120000 }
).trim();

const remoteUrl = 'https://nmserain:' + gitToken + '@github.com/nmserain/n8nworkflows.git';
const workflowsDir = repoPath + '/workflows';
const fullBackupFile = repoPath + '/N8N_GitHub_Daily_Backup.json';

try {
  // Scrub any leaked secrets from files before committing (belt-and-suspenders)
  exec('find ' + workflowsDir + ' -name \'*.json\' -exec sed -i \'s/REDACTED[A-Za-z0-9_]*/REDACTED/g\' {} +');
  exec('sed -i \'s/REDACTED[A-Za-z0-9_]*/REDACTED/g\' ' + fullBackupFile);

  // Nuclear git: rebuild clean history by re-cloning and restoring files
  const tmpDir = '/tmp/n8n-git-work';
  exec('rm -rf ' + tmpDir);

  // Save our clean files to temp before git checkout may overwrite them
  exec('mkdir -p ' + tmpDir + '/wf');
  exec('cp -r ' + workflowsDir + '/. ' + tmpDir + '/wf/');
  exec('cp ' + fullBackupFile + ' ' + tmpDir + '/backup.json');

  // Nuke old .git and re-init for clean history
  exec('rm -rf ' + repoPath + '/.git');
  exec('git -C ' + repoPath + ' init');
  exec('git -C ' + repoPath + ' remote add origin ' + remoteUrl);
  exec('git -C ' + repoPath + ' config user.name "' + gitUserName + '"');
  exec('git -C ' + repoPath + ' config user.email "' + gitUserEmail + '"');

  // Try to base on existing remote history
  try {
    exec('git -C ' + repoPath + ' fetch origin ' + gitBranch + ' --depth=1 --quiet');
    exec('git -C ' + repoPath + ' checkout -b ' + gitBranch + ' origin/' + gitBranch);
  } catch(e) {
    exec('git -C ' + repoPath + ' checkout -b ' + gitBranch);
  }

  // Restore our clean files (overwrite whatever checkout placed)
  exec('mkdir -p ' + workflowsDir);
  exec('cp -r ' + tmpDir + '/wf/. ' + workflowsDir + '/');
  exec('cp ' + tmpDir + '/backup.json ' + fullBackupFile);
  exec('rm -rf ' + tmpDir);

  // Stage and check for changes
  exec('git -C ' + repoPath + ' add workflows/ N8N_GitHub_Daily_Backup.json');
  const staged = exec('git -C ' + repoPath + ' diff --staged --name-only');
  if (!staged) {
    return [{ json: { exitCode: 0, stdout: 'No changes — already up to date', stderr: '' } }];
  }

  let commitMsg = 'backup: ' + workflowCount + ' workflows — ' + timestamp;
  if (removedCount > 0) commitMsg += ' (removed ' + removedCount + ')';

  exec('git -C ' + repoPath + ' commit --no-verify --no-gpg-sign -m "' + commitMsg + '"');
  exec('git -C ' + repoPath + ' push --force -u origin ' + gitBranch);

  return [{ json: { exitCode: 0, stdout: 'Backed up ' + workflowCount + ' workflows', stderr: '' } }];
} catch (error) {
  try { execSync('rm -rf /tmp/n8n-git-work', { encoding: 'utf8' }); } catch(e) {}
  return [{ json: { exitCode: 1, stdout: '', stderr: error.message.slice(0, 500) } }];
}

const workflowCount = $('Process & Save All Files').item.json.workflowCount;
const removedCount = $('Process & Save All Files').item.json.removedCount;
